const gptResponse = $('GPT Content').first().json;
const webhookData = $('Webhook').first().json.body;

const title = gptResponse.title || webhookData.productName || 'Amigurumi';
const description = gptResponse.description || '';
const tags = gptResponse.tags || [];

const PRESETS = {
  'living-sofa': { label: 'Kanepe Ustu', prompt: 'on a cozy beige sofa in a modern living room. Soft cushions, warm ambient lighting.' },
  'living-armchair': { label: 'Koltuk Ustu', prompt: 'on a comfortable armchair in a stylish living room. Warm reading lamp light.' },
  'living-rug': { label: 'Salon Halisi', prompt: 'on a soft fluffy rug in a bright living room. Warm natural light from windows.' },
  'living-coffee-table': { label: 'Sehpa Ustu', prompt: 'on a round wooden coffee table in a living room. Coffee cup nearby, cozy.' },
  'living-tv-unit': { label: 'TV Unitesi', prompt: 'on a modern TV unit shelf in a living room. Clean lines, warm ambient light.' },
  'living-cushion': { label: 'Yastik Yaninda', prompt: 'leaning against a decorative cushion on a sofa. Soft cozy living room.' },
  'bed-white': { label: 'Beyaz Yatak', prompt: 'on a neatly made bed with white soft bedding. Soft morning light.' },
  'bed-colorful': { label: 'Renkli Yatak', prompt: 'on a colorful patterned bedspread. Bright cheerful bedroom.' },
  'nightstand': { label: 'Komodin Ustu', prompt: 'on a bedroom nightstand next to a soft glowing lamp. Evening atmosphere.' },
  'bed-pillow': { label: 'Yastik Ustu', prompt: 'resting on a fluffy white pillow on a bed. Dreamy morning light.' },
  'bedroom-shelf': { label: 'Yatak Odasi Rafi', prompt: 'on a bedroom floating shelf with decorative items. Warm room.' },
  'baby-crib': { label: 'Besik Yaninda', prompt: 'next to a white baby crib in a pastel nursery. Gentle lighting, dreamy.' },
  'baby-changing': { label: 'Bakim Masasi', prompt: 'on a baby changing table in a pastel nursery. Baby accessories nearby.' },
  'baby-rocker': { label: 'Sallanan Koltuk', prompt: 'on a nursing rocking chair in a baby room. Pastel tones, peaceful.' },
  'baby-blanket': { label: 'Bebek Battaniyesi', prompt: 'on a soft baby blanket on the nursery floor. Pastel colors.' },
  'baby-shelf': { label: 'Bebek Rafi', prompt: 'on a baby room wall shelf with small stuffed animals. Pastel decor.' },
  'kids-carpet': { label: 'Cocuk Halisi', prompt: 'on a colorful carpet in a bright childrens room. Toys in soft bokeh.' },
  'kids-playroom': { label: 'Oyun Alani', prompt: 'in a bright playroom surrounded by blurred colorful toys.' },
  'kids-desk': { label: 'Cocuk Masasi', prompt: 'on a childs desk with colorful pencils and books blurred.' },
  'kids-tent': { label: 'Oyun Cadiri', prompt: 'at the entrance of a cute indoor play tent with fairy lights.' },
  'kids-shelf': { label: 'Oyuncak Rafi', prompt: 'on a wooden kids shelf with other toys blurred behind.' },
  'kids-bed': { label: 'Cocuk Yatagi', prompt: 'on a colorful kids bed with cartoon bedding. Cheerful room.' },
  'kitchen-marble': { label: 'Mermer Tezgah', prompt: 'on a clean white marble kitchen counter. Modern kitchen, warm light.' },
  'kitchen-wooden': { label: 'Ahsap Tezgah', prompt: 'on a warm wooden kitchen counter. Rustic farmhouse kitchen.' },
  'dining-table': { label: 'Yemek Masasi', prompt: 'on a wooden dining table in a bright minimalist home.' },
  'breakfast-table': { label: 'Kahvalti Masasi', prompt: 'on a breakfast table with coffee blurred in background. Morning.' },
  'study-desk': { label: 'Calisma Masasi', prompt: 'on a clean modern study desk. Minimalist workspace, bright light.' },
  'study-bookshelf': { label: 'Kitaplik', prompt: 'in front of a cozy bookshelf with colorful books. Warm lighting.' },
  'study-shelf': { label: 'Duvar Rafi', prompt: 'on a modern floating wall shelf in a study. Clean lines.' },
  'fireplace': { label: 'Somine Onu', prompt: 'on a cozy rug in front of a warm fireplace. Golden glow, knit blanket.' },
  'window-sill': { label: 'Pencere Kenari', prompt: 'on a bright window sill with natural daylight streaming in.' },
  'reading-nook': { label: 'Okuma Kosesi', prompt: 'in a cozy reading nook with cushions and throw blanket. Fairy lights.' },
  'candle-setup': { label: 'Mum Isigi', prompt: 'surrounded by soft glowing candles. Warm intimate atmosphere.' },
  'knit-blanket': { label: 'Orgu Battaniye', prompt: 'on a soft chunky knit blanket. Cozy hygge atmosphere.' },
  'home-entrance': { label: 'Giris Holu', prompt: 'on a console table in a home entrance hallway. Mirror blurred behind.' },
  'home-stairs': { label: 'Merdiven', prompt: 'sitting on a wooden staircase step in a cozy home. Warm lighting.' },
  'home-random': { label: 'Ev Rastgele', prompt: 'in a random cozy spot inside a beautiful home. Warm lighting.' },
  'home-floor': { label: 'Ev Zemini', prompt: 'on a clean hardwood floor. Furniture blurred, natural light.' },
  'home-radiator': { label: 'Kalorifer Ustu', prompt: 'on a radiator shelf cover near a window. Warm winter feeling.' },
  'home-bathroom-shelf': { label: 'Banyo Rafi', prompt: 'on a white bathroom shelf next to fluffy towels. Clean bright.' }
};

const SD = { 'simple': 'Very clean simple scene, minimal props.', 'medium': '', 'detailed': 'Rich detailed scene with many props and decorations.' };
const CD = { 'close': 'Close-up shot, toy fills most of frame.', 'medium': '', 'far': 'Wide shot showing full room, toy smaller in frame.' };
const TS = { 'small': 'Toy appears small in scene.', 'medium': '', 'large': 'Toy is prominently large in frame.' };
const CA = { 'front': 'Straight front view.', 'front-45': '45-degree front angle.', 'side': 'Side angle.', 'top': 'Top-down view.', 'low': 'Low angle looking up.' };
const TP = { 'keep': '', 'sitting': 'Toy in cute sitting position.', 'standing': 'Toy standing upright.', 'lying': 'Toy lying on its side.', 'tilted': 'Toy slightly tilted playfully.' };

const opts = webhookData.promptOptions || {};
const extraNotes = opts.extraNotes ? ' ' + opts.extraNotes : '';
const sett = webhookData.settings || {};
const promptRules = sett.promptRules || 'Keep the amigurumi toy EXACTLY as it is. Only change the background. Professional Etsy product photography.';
const proxyUrl = webhookData.callbackUrl.replace('/api/webhook/n8n', '/api/gemini-image');
const imageUrl = webhookData.referenceImageUrl;
const concepts = webhookData.concepts || [];
const items = [];

for (const concept of concepts) {
  const bgId = concept.backgroundId;
  const variants = concept.variants || [concept.variant || {}];
  const preset = PRESETS[bgId];
  if (!preset) continue;

  for (let vi = 0; vi < variants.length; vi++) {
    const v = variants[vi];
    const variantParts = [
      SD[v.sceneDetail] || '',
      CD[v.cameraDistance] || '',
      TS[v.toySize] || '',
      CA[v.cameraAngle] || CA['front-45'],
      TP[v.toyPose] || ''
    ].filter(Boolean).join(' ');

    const variationHint = variants.length > 1 ? ' Create a unique variation (variation ' + (vi+1) + ' of ' + variants.length + '), slightly different composition and exact placement.' : '';

    const fullPrompt = 'Edit this image: Remove the background and place the amigurumi toy ' + preset.prompt + ' ' + variantParts + ' ' + promptRules + variationHint + extraNotes;

    items.push({ json: { proxyUrl, imageUrl, prompt: fullPrompt, backgroundId: bgId, backgroundLabel: preset.label + (variants.length > 1 ? ' #' + (vi+1) : ''), title, description, tags, productId: webhookData.productId, callbackUrl: webhookData.callbackUrl, secret: webhookData.secret } });
  }
}

if (items.length === 0) throw new Error('No valid concepts');
return items;

const crypto = require('crypto');
const CLOUD_SECRET = '9XsIgOi01RoxfE3PnRi0zWuZkEM';
const allResponses = $input.all();
const fanOutItems = $('Fan Out').all();
const results = [];

for (let i = 0; i < allResponses.length; i++) {
  const response = allResponses[i].json;
  const bgInfo = fanOutItems[i]?.json;
  if (!bgInfo) continue;

  const imageBase64 = response.imageBase64;
  if (!imageBase64) continue;

  const ts = Math.floor(Date.now() / 1000).toString();
  const folder = 'amigurumi/gemini';
  const sig = crypto.createHash('sha1').update('folder=' + folder + '&timestamp=' + ts + CLOUD_SECRET).digest('hex');
  results.push({ json: { imageBase64, cloudTs: ts, cloudSig: sig, backgroundId: bgInfo.backgroundId, backgroundLabel: bgInfo.backgroundLabel, title: bgInfo.title, description: bgInfo.description, tags: bgInfo.tags, productId: bgInfo.productId, callbackUrl: bgInfo.callbackUrl, secret: bgInfo.secret } });
}

if (results.length === 0) {
  const bg = fanOutItems[0]?.json || {};
  return [{ json: { noImages: true, productId: bg.productId, callbackUrl: bg.callbackUrl, secret: bg.secret, title: bg.title || '', description: bg.description || '', tags: bg.tags || [] } }];
}
return results;

const uploadResults = $input.all();
const prepItems = $('Prep Upload').all();
const images = [];
let title = '', description = '', tags = [], productId = '', callbackUrl = '', secret = '';
for (let i = 0; i < prepItems.length; i++) {
  const prep = prepItems[i].json;
  const upload = uploadResults[i]?.json;
  if (!productId) { title = prep.title || ''; description = prep.description || ''; tags = prep.tags || []; productId = prep.productId; callbackUrl = prep.callbackUrl; secret = prep.secret; }
  if (upload?.secure_url) { images.push({ url: upload.secure_url, backgroundId: prep.backgroundId, backgroundLabel: prep.backgroundLabel }); }
}
if (!callbackUrl) { const f = prepItems[0]?.json || {}; callbackUrl = f.callbackUrl; secret = f.secret; productId = f.productId; }
return [{ json: { callbackUrl, callbackBody: { secret, type: 'generate-result', productId, images, title, description, tags } } }];
